import express from "express";

const app = express(); //instanciranje aplikacije
const port = 3000; // port na kojem će we server slušati

//razumije json
app.use(express.json());

//popis timova
app.get('/timovi', (req, res) => {
    let timovi = [
        {id: 1, ime_tima: 'brzi', veličina_tima: 10, sport: 'id'},
        {id: 1, ime_tima: 'spori', veličina_tima: 8, sport: 'id'},
    ];
    res.status(200);
    res.send(timovi);
});

//dobivanje svih terena
app.get('/tereni', (req, res) => {   
    let tereni = [
        {id: '1', mjesto: 'Stari Pazin', izgled: 'travnato', sport: 'id', prostor: 'zatvoreni'},
        {id: '2', mjesto: 'Pazin', izgled:  'cement', sport: 'id', prostor: 'otvoreni'},
    ];
    res.status(200);
    res.send(tereni);   
});

//dobivanje slobodnih terena terena
app.get('/zauzeti', (req, res) => {
    //let zauzet = {teren_id: 1, zauzeto: 'slobodno'};
    /*{zauzeto} = req.params;
    if(zauzeto == 'slobodno'){
        res.status(200);
        res.send(tereni);
    }*/
});

//dobivanje odredenog terena
app.get('/tereni/:id', (req, res) => {
    let teren = {id: '2', mjesto: 'Pazin', izgled:  'cement', zauzeto: 1, sport: 'id', prostor: 'otvoreni'};
    console.log("Teren: ", req.params.id);
    res.status(200);
    res.send(teren);
});

//nadodavanje terena
app.post('/tereni', (req, res) => {
    res.status(201);
    res.send();
});

//popis sportova koji se mogu igrat na odredenom terenu
app.get('/tereni/:sport', (req, res) => {
    console.log("Sportovi na terenu: ", req.params.sport);
    res.status(200);
    res.send(sport);
});

//zauzeti prostori prostori
app.get('/zauzeti/:zauzeto', (req, res) => {
    /*{zauzeto} = req.params;
    if(zauzeto == 'zauzeto'){
        console.log("Zauzeti tereni: ", req.params.zauzeto);
        res.status(200);
        res.send(tereni);
    }*/
});

//promjena zauzetosti terena
app.patch('/zauzeti/:zauzeto', (req, res) => {
    console.log("Promjena zauzetosti ", req.param.zauzeto)
    res.status(200);
    res.send();

});

//promjena rezervacije
app.delete('/zauzeti/zauzeto', (req, res) => {

    res.status(200);
    res.send();
});

//ispis u konzoli
app.listen(port, () => console.log(`Slušam na portu ${port}!`))
